parameters.jsCode:
/*
  Aislamos las 4 fuentes en un formato comun.
  - `Error Trigger` trae data en `{ execution, workflow }`
  - `Webhook / Execute / Manual` traen un payload manual similar.
*/
const incoming = $input.first()?.json || {};
const isSystemError = !!incoming.execution;

// Mapeamos el payload
const payload = isSystemError ? incoming : incoming.body || incoming;

return {
  workflow_id: payload.workflow?.id || "UNKNOWN",
  workflow_name: payload.workflow?.name || "UNKNOWN",
  execution_id: payload.execution?.id || "MANUAL_TEST_ID",
  error_message: payload.execution?.error?.message || payload.error_message || "Unknown Error",
  error_stack: payload.execution?.error?.stack || "",
  last_node: payload.execution?.lastNodeExecuted || "",
  mode: payload.execution?.mode || "manual"
};

